insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'power-shine-nablyszczajacy-lakier-do-wlosow-500-ml', 'Power Shine · nabłyszczający lakier do włosów 500 ml', 'Lakier nabłyszczający z mocnym utrwaleniem, do wszystkich rodzajów włosów.', 'Profesjonalny lakier stylizacyjny z linii I-FIX, który modeluje i utrwala fryzurę, tworząc mikrofilm ochronny oraz efekt intensywnego blasku. Zalecany do wszystkich typów włosów, pozwala na formowanie w wybrany kształt z wykończeniem pełnym połysku.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'stylizacja'), '/produkty/power-shine-500ml.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/10/IfixPowerShine.png"}', true, ''
