insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'ifix-shape-it-guma-modelujaca-100ml', 'iFix Shape It - guma modelująca 100ml', 'Mocna guma modelująca do stylizacji detali i tekstur.', 'Stylizacyjna guma o mocnym chwytcie, przeznaczona do kreowania wyrazistych struktur, podkreślania detali i definiowania fryzury · idealna dla krótszych cięć lub miejscowych akcentów. Pozostawia włosy plastyczne i pod kontrolą.',
