insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'polishing-serum-serum-wygladzajace-i-nawilzajace-150ml', 'Polishing Serum - serum wygładzające i nawilżające 150ml', 'Wygładzające serum bez spłukiwania, które ujarzmia niesforne włosy i dodaje blasku.', 'Koncentrat serum stylizacyjno-pielęgnacyjny, stworzony do włosów średnich i grubych · wygładza puszące się i oporne kosmyki, skraca czas suszenia oraz nadaje jedwabisty połysk. Zawiera olej ze słodkich migdałów i olejek z pestek winogron, które działają zmiękczająco i przeciwutleniająco.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'stylizacja'), '/produkty/IfixPolishing.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/10/IfixPolishing.png"}', true, ''
