insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'biological-wawing-system-pn-wlosy-zniszczone-lub-naturalne-100mlx2', 'Biological Wawing System PN - włosy zniszczone lub naturalne 100ml x2', 'Biologiczny system trwałej ondulacji bez amoniaku i kwasu tioglikolowego, wzmacnia włosy dzięki proteinom sojowym i aminokwasom kolagenu morskiego.', 'System przeznaczony do naturalnych i zniszczonych włosów · obejmuje emulsję ondulacyjną i neutralizator, które po nawinięciu na wałki pozwalają stworzyć trwałe fale lub loki. Formuła wzbogacona proteinami sojowymi oraz aminokwasami kolagenu morskiego działa odżywczo i poprawia elastyczność włosa, zapobiegając rozdwajaniu końcówek i utrzymując strukturę włosa nawet po zabiegu',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'produkty-techniczne'), '/produkty/WavingSystem.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/10/WavingSystem.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'regal-wash-shampoo', 'Regal Wash Shampoo', 'Szampon Regal Wash został stworzony, by wspierać walkę z przerzedzaniem i osłabieniem włosów. Zawiera wodę termalną, keratynę, aminokwasy (m.in. argininę i prolinę) oraz kompleks witamin (np. niacynamid, pro-witamina B5), które oczyszczają skórę głowy, stymulują mikrokrążenie i wzmacniają strukturę włosa od cebulki.', 'Delikatny, a jednocześnie skuteczny szampon przeciw wypadaniu włosów, wspierający zdrową skórę głowy i mocniejsze korzenie.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/KerabondRegalWashShampoo.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/10/KerabondRegalWashShampoo.png"}', true, 'Pojemność'
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'regal-life-ampulki-kuracja-12-x-6-ml', 'Regal Life · ampułki - kuracja 12 x 6 ml', 'Ampułki Regal Life to intensywna kuracja, która wzmacnia włókno włosa, stymuluje skórę głowy i pomaga zapobiegać wypadaniu włosów.', 'Ampułki Regal Life zawierają liposomy, Bioprolinę oraz prowitaminy B5 i są przeznaczone do włosów cienkich, osłabionych i ze skłonnością do wypadania. Dzięki aktywnej formule, kuracja stymuluje mikrokrążenie skóry głowy, wzmacnia cebulki włosowe oraz poprawia tonus i strukturę włosa · dla widocznej poprawy gęstości i komfortu skóry głowy.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/KerabondRegalLife.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/10/KerabondRegalLife.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'liposomowe-farby-do-wlosow-1-1-5-100ml', 'Liposomowe farby do włosów 1:1.5 100ml', 'Kompaktowa farba do włosów z wodą termalną w jakości HD.', 'Kompaktowa farba do włosów z wodą termalną w jakości HD. LHC Kolor HD to najbardziej innowacyjny produkt na rynku fryzjerskim. System aktywacji liposomowej oraz woda termalna i olej arganowy gwarantują najwyższą jakość i trwałość koloru. Takie połączenie składników przemienia zabieg koloryzacji w prawdziwy zabieg kosmetyczny, pozostawiając włosy lśniące i świetliste. Jest to nowa generacja koloru o niskiej zawartości amoniaku, przyjemnym zapachu i delikatnej konsystencji. Kremowo-żelowa formuła łatwa w przygotowaniu. Keratyna odbudowująca o niskiej masie cząsteczkowej ochrania strukturę włosów przed zniszczeniem. Synergia minerałów z ultra-czystymi pigmentami zapewnia doskonałe pokrycie siwych włosów i maksymalną trwałość koloru oraz ich blask. 75 odcieni (standardowe i straightlight) z możliwością stworzenia 792 kombinacji kolorystycznych. Liposomowy nośnik pigmentów i substancji odżywczych. Gwarancja całkowitego pokrycia siwych włosów. Farby nie wymagające stosowania produktów zakwaszających.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'koloryzacja'), '/produkty/LiposomeHairColor.png', '{"https://cbh-polska.pl/wp-content/uploads/2021/07/LHC-astuccio-e-tubo-def-e1509388439323.png"}', true, 'Kolor'
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'botanical-farby-permanentne-bez-amoniaku-100-ml-1-1', 'Botanical - farby permanentne bez amoniaku 100 ml 1:1', 'Trwała farba bez amoniaku i P-fenylenodiaminy, która rozjaśnia włosy do 3 poziomów, gwarantując pełne pokrycie siwych oraz głęboki, żywy kolor.', 'Formuła Botanical Hair Color została stworzona z myślą o pielęgnacji · bez amoniaku i P-fenylenodiaminy, z bogactwem składników roślinnych takich jak olej kakaowca oraz ekstrakty z hamamelisu, babki, rumianku, brzozy, skrzypu, kasztanowca i dziurawca, które odżywiają, nawilżają i tonizują włosy. Farba zapewnia równomierne pokrycie siwych włosów, nie plami skóry i łatwo się spłukuje, a przy tym nadaje włosom elastyczność, blask i naturalną jasność',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'koloryzacja'), '/produkty/BotanicalHairColor.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/10/BotanicalHairColor.png"}', true, 'Botanical Kolor'
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'active-lotion-balsam-katalizujacy-3-1l', 'Active Lotion · balsam katalizujący 3% 1L', 'Balsam katalizujący 3% Active Lotion to profesjonalny preparat wspomagający zabiegi chemiczne, który aktywuje i utrwala strukturę włosa, zapewniając długotrwały efekt i optymalną pielęgnację.', 'Active Lotion 3% działa jako katalizator w zabiegach fryzjerskich, wzmacniając włókno włosa dzięki starannie dobranym składnikom aktywnym i odpowiedniemu stężeniu. Kremowa formuła przygotowuje włosy do kolejnych etapów zabiegu, zapewniając równomierne działanie, poprawę wytrzymałości i trwałość efektu stylizacji. Idealny do zastosowania w profesjonalnych warunkach salonowych.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'koloryzacja'), '/produkty/ActiveLotion.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/ActiveLotion.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'color-clean-chusteczki', 'Color Clean chusteczki', 'Chusteczki do zmywania zabrudzeń po koloryzacji', 'Kultowe chusteczki do zmywania zabrudzeń po koloryzacji  · teraz w nowej formule! Skuteczniejsze działanie, ochrona skóry dzięki aloesowi i witaminie B5 oraz przepiękny zapach.',
  (select id from brands where slug = 'color-clean'), (select id from categories where slug = 'koloryzacja'), 'https://cbh-polska.pl/wp-content/uploads/2025/11/CC-scaled.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/CC-scaled.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'bleach-powder-diamond-puder-szary-500g', 'Bleach Powder Diamond / puder szary / 500g', 'Profesjonalny proszek rozjaśniający „Diamond”, bezpyłowy i o wysokiej mocy działania, który rozjaśnia włosy nawet do 9 poziomów, jednocześnie neutralizując niepożądane żółte odcienie.', '„Diamond Bleach Powder” to ultra-wysokiej jakości rozjaśniacz przeznaczony dla salonów fryzjerskich, oferujący aż do 8·9 poziomów podniesienia koloru i wolny od pyłu dla bezpieczniejszej pracy. Dzięki specjalnej formule z „Diamond Technology” lub składnikami kondycjonującymi, minimalizuje obciążenie struktury włosa, zapobiega nadmiernemu pęcznieniu i zapewnia czystą, jasną bazę pod koloryzację. Idealny dla technik typu balayage, pełnych głów czy kreatywnego rozjaśniania, kiedy wymagany jest maksymalny efekt.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'koloryzacja'), '/produkty/DarkDiamond.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/DarkDiamond.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'bleach-powder-plus-puder-ziolowy-500g', 'Bleach Powder Plus / puder ziołowy / 500g', 'Profesjonalny proszek rozjaśniający „Dust Free”, który pozwala rozjaśnić włosy do 6 poziomów z jednoczesną neutralizacją żółtych tonów.', 'Bleach Powder Plus to innowacyjna formuła proszku rozjaśniającego o właściwościach „dust-free”, przeznaczona do użytku profesjonalnego. Dzięki fioletowym pigmentom neutralizuje typowe żółte odcienie powstające przy rozjaśnianiu, jednocześnie umożliwiając podniesienie koloru aż do 6 tonów.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'koloryzacja'), '/produkty/BleachPowder.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/BleachPowder.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'kerabond-zestaw-podrozny', 'Kerabond · zestaw podróżny', 'Zestaw podróżny Kerabond · szampon Hydro-Keratin 100 ml + maska Kerabonding 75 ml + olejek Multivitamin · intensywnie odbudowuje włosy po zabiegach chemicznych, przywracając im blask i siłę.', 'Zestaw Kerabond Travel Kit marki Chenice został stworzony z myślą o włosach zniszczonych, po koloryzacji lub zabiegach fryzjerskich · kolejno: szampon Hydro-Keratin oczyszcza i przygotowuje strukturę włosa, maska Kerabonding głęboko odbudowuje mostki keratynowe, a olejek Multivitamin wprasowuje się w końcówki, dostarczając skoncentrowaną dawkę witamin i minerałów. Efekt to wyraźnie mocniejsze, elastyczne i pełne blasku włosy · idealny do stosowania w podróży lub jako kuracja podtrzymująca w domu.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/KerabondHydroKeratinSet.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/KerabondHydroKeratinSet.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'kerabond-hydrokeratin-shampoo', 'Kerabond Hydrokeratin Shampoo', 'Delikatny szampon odbudowujący z keratyną i intensywnym nawilżeniem, idealny dla włosów suchych, zniszczonych lub po zabiegach chemicznych.', 'Hydro-Keratin Shampoo skutecznie oczyszcza, jednocześnie wnikając w strukturę włosa dzięki aktywowanej keratynie i składnikom nawilżającym. Przywraca włosom elastyczność, redukuje łamliwość i puszenie się, pozostawiając je miękkie, gładkie i łatwiejsze w układaniu.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/KerabondHydroKeratinShampoo.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/KerabondHydroKeratinShampoo.png"}', true, 'Pojemność'
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'kerabond-multi-vitamin-oil', 'Kerabond Multi-Vitamin Oil', 'Olejek rekonstrukcyjny z linii Kerabond, zawierający kompleks multiwitamin i keratynę, który odbudowuje włosy, nadając im miękkość, sprężystość i wyjątkowy połysk.Multi-Vitamin Oil marki Chenice to zaawansowany olejek odbudowujący, opracowany z myślą o włosach zniszczonych zabiegami chemicznymi. Zawiera skoncentrowany kompleks witamin i minerałów oraz technologię liposomową, która dostarcza substancje aktywne w głąb struktury włosa · chroni przed starzeniem, redukuje łamliwość i rozdwajanie końcówek, a przy tym intensywnie nawilża i nabłyszcza.', 'Multi-Vitamin Oil marki Chenice to zaawansowany olejek odbudowujący, opracowany z myślą o włosach zniszczonych zabiegami chemicznymi. Zawiera skoncentrowany kompleks witamin i minerałów oraz technologię liposomową, która dostarcza substancje aktywne w głąb struktury włosa · chroni przed starzeniem, redukuje łamliwość i rozdwajanie końcówek, a przy tym intensywnie nawilża i nabłyszcza.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/KerabondHydroKeratinOil.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/KerabondHydroKeratinOil.png"}', true, 'Pojemność'
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'kerabond-maska', 'Kerabond maska', 'Maska Kerabonding to intensywnie odbudowująca kuracja z keratyną i aminokwasami, przeznaczona dla włosów zniszczonych zabiegami chemicznymi · przywraca im miękkość, sprężystość i blask.', 'Maska Kerabonding została opracowana z myślą o głębokiej odbudowie struktury włosa · technologia Liposom® i aktywne aminokwasy wnikają w głąb włosa, wypełniając ubytki keratyny spowodowane rozjaśnianiem, farbowaniem lub innymi zabiegami chemicznymi. Dzięki temu włosy odzyskują równowagę pH, stają się elastyczne, mniej podatne na łamanie i uzyskują zdrowy wygląd z naturalnym połyskiem.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'odbudowa-wlosow'), '/produkty/KerabondHydroKeratinMask.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/KerabondHydroKeratinMask.png"}', true, 'Pojemność'
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'keep-in-color-moisturizing-wash-shampoo', 'Keep in Color Moisturizing Wash Shampoo', 'Szampon po koloryzacji, który delikatnie oczyszcza, silnie nawilża oraz pomaga utrzymać kolor włosów świeży i pełen blasku.', 'Keep In Color Moisturizing Wash to profesjonalna formuła przeznaczona dla włosów po farbowaniu · zawiera składniki aktywne, które przenikają w strukturę włosa, działając zmiękczająco, nawilżająco i odżywczo, jednocześnie respektując naturalną hydro-lipidową warstwę skóry. Efekt: włosy są miękkie, elastyczne, lśniące, a kolor utrzymuje się dłużej, nie blaknie i wygląda profesjonalnie.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/KeepinColorShampoo.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/KeepinColorShampoo.png"}', true, 'Pojemność'
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'keep-in-color-moisturizing-mask', 'Keep in Color Moisturizing Mask', 'Maska po koloryzacji, bogata w wodę termalną, przeznaczona dla włosów suchych i farbowanych · intensywnie nawilża, chroni kolor i nadaje włosom jedwabistą miękkość.', 'Keep in Color Moisturizing Mask została stworzona z myślą o włosach farbowanych, suchych lub odwodnionych. Jej formuła oparta na wodzie termalnej, polimerach ochronnych, aloesie i witaminie E pomaga utrzymać odpowiedni poziom nawilżenia, przedłużyć intensywność koloru oraz chronić przed promieniowaniem UVA/UVB i zanieczyszczeniami. Dodatkowo ułatwia rozczesywanie, nadaje blask i sprawia, że włosy stają się wyjątkowo miękkie i jedwabiste w dotyku.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'odbudowa-wlosow'), '/produkty/KeepinColorMask.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/KeepinColorMask.png"}', true, 'Pojemność'
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'synergy-wash-szampon-antylojotokowy', 'Synergy Wash · szampon antyłojotokowy', 'Szampon Synergy Wash skutecznie reguluje nadmierne wydzielanie sebum i zwalcza łupież, jednocześnie łagodząc stany zapalne skóry głowy.', 'Synergy Wash to liposomowy szampon z formułą zawierającą m.in. Piroctone Olamine i Capryloyl Glycina, przeznaczony dla włosów tłustych i ze skłonnością do łupieżu. Dzięki zawartości ziołowych ekstraktów i naturalnej lecytyny działa antybakteryjnie, koi podrażnienia skóry głowy i zapobiega nawrotom łojotoku oraz łupieżu.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'szampony'), '/produkty/KerabondSynergyWashShampoo.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/KerabondSynergyWashShampoo.png"}', true, 'Pojemność'
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'bottox-effect-4x50-ml', 'Bottox Effect 4x50 ml', 'Kuracja Bottox Effect to intensywna regeneracja włosów każdego rodzaju · głębokie nawilżenie dzięki kwasowi hialuronowemu, odbudowa keratyną i kolagenem oraz natychmiastowy połysk i miękkość.', 'Bottox Effect to profesjonalna kuracja włosów, która dzięki zawartości kwasu hialuronowego potrafi utrzymać dużą ilość wody we włosach, zapewniając im głębokie nawilżenie. Dodatkowo kolagen i keratyna wspierają odbudowę włókna włosa, a olej pistacjowy działa jako naturalny anty‑aging, wzmacniając i chroniąc włosy przed zniszczeniem. Rezultatem są włosy gładkie, błyszczące i odżywione · idealne jako zamiennik zabiegów prostujących.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/BottoxSet.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/BottoxSet.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'clarifying-shampoo-500ml', 'Clarifying Shampoo 500ml', 'Szampon oczyszczający o pH 9 z keratyną i składnikami aktywnymi, przeznaczony jako przygotowanie do zabiegu · usuwa osady i otwiera łuski włosa dla lepszego wchłaniania kuracji.', 'Ten keratynowy szampon clarifying o wysokim pH (pH 9) skutecznie usuwa pozostałości po produktach stylizujących, nadmiar sebum i zanieczyszczenia, otwierając łuski włosa i tworząc optymalną bazę pod zabiegi regeneracyjne lub prostujące. Dzięki zawartości keratyny oraz składników wspierających przygotowuje włosy do dalszych etapów pielęgnacji, poprawiając przyczepność aktywnych substancji. Idealny jako pierwszy krok w profesjonalnej kuracji, zapewnia czystą, przygotowaną powierzchnię włosa gotową na działanie kolejnych produktów.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/CalrifyingShampoo.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/CalrifyingShampoo.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'greencare-szampon-250ml', 'Greencare szampon 250ml', 'Szampon GREENCARE 250 ml to profesjonalna kuracja przeciw łupieżowi i nadmiernej produkcji sebum · skutecznie oczyszcza skórę głowy i włosy, przywracając im uczucie świeżości.', 'Szampon GREENCARE działa wielotorowo: dzięki kompozycji aktywnych aminokwasów (m.in. cysteina, ornityna, biotyna, metionina) wspiera oczyszczanie i normalizację skóry głowy oraz zapobiega problemom takim jak łupież, przetłuszczanie się i osłabienie włosów. W efekcie włosy są lżejsze, mniej obciążone i wyglądają na zdrowsze · linia została specjalnie zaprojektowana, by wspierać skórę głowy wymagającą głębszego wsparcia.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/GreenLifeShampoo.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/GreenLifeShampoo.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'greencare-fluid-100ml', 'Greencare fluid 100ml', 'Fluid GREENCARE 100 ml to intensywna kuracja oczyszczająca skóry głowy, przeznaczona do włosów z problemami takimi jak przetłuszczanie i łupież.', 'Fluid GREENCARE działa detoksykująco i rewitalizująco · poprawia mikrokrążenie skóry głowy oraz wspiera jej czystość i zdrowy wygląd. Zawiera składniki aktywne, które pomagają zwalczać nadmierne wydzielanie sebum oraz problemy związane z łupieżem, oferując profesjonalną kurację skóry głowy.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/GreenLifeLotion.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/GreenLifeTreatment.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'greencare-emulsja-100-ml', 'Greencare emulsja 100 ml', 'Emulsja GREENCARE 100 ml to lekki balsam oczyszczający i tonizujący do skóry głowy, który nie wymaga spłukiwania, wspomagając codzienną pielęgnację i świeżość włosów.', 'GREENCARE Emulsja 100 ml to innowacyjny produkt łączący działanie oczyszczające i tonizujące · wzmacnia skórę głowy, reguluje wydzielanie sebum i łagodzi podrażnienia. Formuła bez spłukiwania ułatwia codzienną pielęgnację, pozostawiając włosy lekkie, świeże i gotowe do stylizacji, jednocześnie poprawiając komfort skóry głowy.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/GreenLifeTreatment.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/GreenLifeTreatment.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'urbn-puryfing-shampoo', 'Urbn Puryfing Shampoo', 'Szampon URBN Purifying 1000 ml to profesjonalna kąpiel oczyszczająca, która usuwa zanieczyszczenia środowiskowe i nadmiar sebum, pozostawiając włosy lekkie i świeże.', 'Formuła URBN Purifying Shampoo zawiera likopen HYDROPOM pozyskiwany ze skórek pomidorów, który działa detoksykująco i chroni włosy oraz skórę głowy przed szkodliwym wpływem środowiska. Szampon skutecznie usuwa nadmiar sebum, osady i resztki produktów, odblokowując pory skóry głowy i przywracając uczucie odświeżenia oraz czystości.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/UrbanShampoo.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/UrbanShampoo.png"}', true, 'Pojemność'
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'urbn-nourishing-maska', 'Urbn Nourishing maska', 'Maska URBN Nourishing to intensywna kuracja na bazie składników przeciw‑zanieczyszczeniowych (m.in. likopen ze skórek pomidorów), która odżywia włosy, przywraca im siłę i blask.', 'Formuła URBN Nourishing Mask zawiera likopen o działaniu detoksykującym oraz filtr UV, a także proteiny pszenicy i ryżu, które regenerują i wzmacniają włosy narażone na zanieczyszczenia środowiska. Chenice +1 Dzięki temu włosy stają się gładkie, bardziej podatne na rozczesywanie i odzyskują zdrowy połysk · idealna jako ostatni krok po oczyszczającym szamponie z tej samej linii.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/UrbanMask.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/UrbanMask.png"}', true, 'Pojemność'
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'urbn-whytwelve-150-ml', 'Urbn Whytwelve 150 ml', 'Wielofunkcyjny spray leave‑in WHYTWELVE 150 ml to lekkie wykończenie pielęgnacyjne z działaniem detoksykującym, który kondycjonuje, nabłyszcza i chroni włosy przed zanieczyszczeniami.', 'Spray WHYTWELVE zawiera likopen o działaniu przeciwzanieczyszczeniowym oraz olej arganowy i białka ryżu, pszenicy i jedwabiu, które wspierają odbudowę i nadają elastyczność włóknu włosa. Formuła „12 efektów w 1 produkcie” obejmuje m.in. kondycjonowanie, nabłyszczanie, ochronę koloru, termoochronę i zapobieganie rozdwajaniu się końcówek · może być stosowana zarówno na mokre, jak i suche włosy.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/UrbanWhyTwelve.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/UrbanWhyTwelve.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'urbn-nourishing-mousse-200-ml', 'Urbn Nourishing Mousse 200 ml', 'Odżywcza pianka do stylizacji, która nawilża, wygładza i nadaje włosom lekkość oraz naturalny blask bez obciążania.', 'URBN NOURISHING MOUSSE to lekka, odżywcza pianka przeznaczona do codziennej stylizacji i pielęgnacji włosów. Jej formuła pomaga nawilżyć i wygładzić pasma, poprawiając ich elastyczność oraz ułatwiając modelowanie. Pianka nadaje włosom miękkość, sprężystość i naturalny połysk, jednocześnie zachowując ich lekkość i objętość. Idealnie sprawdzi się zarówno do włosów prostych, jak i falowanych, pomagając kontrolować puszenie i podkreślić naturalną strukturę fryzury. Produkt nie skleja włosów i nie pozostawia osadu, dzięki czemu fryzura wygląda świeżo i naturalnie przez cały dzień. Sposób użycia Nałożyć niewielką ilość pianki na wilgotne, osuszone ręcznikiem włosy. Rozprowadzić równomiernie, a następnie przystąpić do stylizacji lub suszenia według potrzeb.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'odbudowa-wlosow'), '/produkty/UrbanMousse.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/11/UrbanMousse-2.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'zel-koloryzujacy-semipermanentny', 'Żel koloryzujący semipermanentny', 'Pół‑trwała koloryzacja włosów o intensywnych odcieniach', 'Chenice Vitamin Colors to pół‑trwałe koloryzacje włosów w intensywnych, kreatywnych odcieniach, idealne dla osób, które chcą dodać włosom wyrazistego stylu i modowego charakteru. Paleta obejmuje Niebieski, Różowy, Fioletowy, Szary, Jasnoczerwony i Fuksja · kolory, które możesz mieszać ze sobą, by stworzyć unikalne efekty. Formuła farb Vitamin Colors nie zawiera amoniaku i nie wymaga dodawania oksydantu, dzięki czemu aplikacja jest szybka i wygodna. Produkt najlepiej sprawdza się na jasnych lub rozjaśnionych włosach, gdzie intensywność pigmentów jest najbardziej widoczna. Kolory utrzymują się przez kilka myć, stopniowo się wypłukując, co daje efekt miękkiej transformacji i kreatywnego miksu barw bez długotrwałego zobowiązania.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'koloryzacja'), '/produkty/VitaminColors.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/12/VitaminColors.png"}', true, 'Kolor'
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'karta-kolorow', 'Karta kolorów', 'Profesjonalna karta kolorów Chenice umożliwia precyzyjny dobór odcienia farby do włosów. Niezastąpione narzędzie w pracy stylisty oraz przy świadomym wyborze koloru przez klienta.', 'Karta kolorów Chenice to praktyczne i profesjonalne narzędzie, które ułatwia dokładny dobór odcienia farby do włosów. Zawiera pełną paletę kolorów dostępnych w ofercie Chenice, umożliwiając realistyczną ocenę tonu, głębi i intensywności pigmentu przed koloryzacją. Dzięki fizycznym próbom kolorów karta pozwala: precyzyjnie dobrać odcień do typu urody i oczekiwań klienta, porównać kolory bazowe, refleksy oraz odcienie specjalne, uniknąć nieporozumień przy wyborze koloru farby, usprawnić pracę w salonie fryzjerskim oraz sprzedaż detaliczną. Karta kolorów Chenice sprawdzi się zarówno w profesjonalnych salonach fryzjerskich, jak i przy sprzedaży farb klientom indywidualnym, którzy chcą świadomie wybrać odpowiedni odcień. To niezbędne wsparcie w planowaniu koloryzacji i prezentacji oferty kolorystycznej marki Chenice.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'akcesoria-fryzjerskie'), '/produkty/LiposomeHairColorCart.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/12/Cartella-Liposome_copertina-1024x1024-1.png","https://cbh-polska.pl/wp-content/uploads/2025/12/Cartella-Liposome_interna4-1024x284-1.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'karta-kolorow-botanical', 'Karta kolorów Botanical', 'Profesjonalna karta kolorów Botanical umożliwia precyzyjny dobór odcieni farb i produktów koloryzujących z linii Botanical. Idealna do pracy w salonie oraz świadomego wyboru koloru.', 'Karta kolorów Botanical to praktyczne narzędzie stworzone z myślą o profesjonalnych fryzjerach oraz klientach, którzy oczekują precyzyjnego i świadomego doboru koloru. Zawiera pełną paletę odcieni dostępnych w linii Botanical, inspirowanej naturalnymi tonami i roślinną koloryzacją. Fizyczne próbki kolorów pozwalają realnie ocenić: odcień, głębię i intensywność koloru, naturalność tonów oraz refleksy, dopasowanie koloru do typu włosów i oczekiwanego efektu. Karta kolorów Botanical ułatwia planowanie koloryzacji, minimalizuje ryzyko nietrafionego wyboru koloru oraz usprawnia komunikację z klientem. Doskonale sprawdzi się w profesjonalnych salonach fryzjerskich oraz punktach sprzedaży oferujących produkty koloryzujące Botanical.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'akcesoria-fryzjerskie'), 'https://cbh-polska.pl/wp-content/uploads/2025/12/Botanical-Hair-Color-Cart.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/12/Botanical-Hair-Color-Cart.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'anti-age-complex-c18', 'Anti-Age Complex C18', 'ANTI-AGE COMPLEX C18 to lekka, płynna emulsja o działaniu przeciwstarzeniowym i regenerującym. Nadaje włosom jedwabistą miękkość, objętość i naturalny blask, bez ich obciążania.', 'ANTI-AGE COMPLEX C18 to miękka i lekka emulsja o płynnej konsystencji, która łatwo się rozprowadza i szybko wchłania. Została stworzona z myślą o pielęgnacji włosów wymagających regeneracji i ochrony przed oznakami starzenia. Formuła produktu działa przeciwstarzeniowo i odbudowująco, poprawiając kondycję włosów na całej długości. Włosy stają się wyraźnie gładsze, bardziej sprężyste i pełne objętości, a ich powierzchnia nabiera zdrowego połysku i jedwabistego wykończenia. Emulsja nie wymaga spłukiwania, dzięki czemu idealnie sprawdza się jako etap pielęgnacji przed stylizacją. Nie obciąża włosów, ułatwia ich rozczesywanie i przygotowuje do suszenia lub modelowania. Sposób użycia Po umyciu włosów szamponem nałóż niewielką ilość produktu na wilgotne, osuszone ręcznikiem włosy. Rozprowadź równomiernie pasmo po paśmie, od końcówek w kierunku nasady i odwrotnie. Pozostaw na 4·5 minut, aby ułatwić wchłanianie. Nie spłukuj. Następnie wysusz włosy wybraną techniką.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/AntiAge.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/12/AntiAge.png"}', true, 'Pojemność'
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'greencare-zestaw-fluid-szampon-emulsja-100-ml', 'Greencare zestaw · fluid, szampon, emulsja 100 ml', 'GREENCARE Zestaw to profesjonalny system pielęgnacyjny składający się z fluidu, szamponu i emulsji, stworzony z myślą o regeneracji, ochronie i przywróceniu równowagi włosom oraz skórze głowy. Idealny po zabiegach technicznych i do intensywnej pielęgnacji.', 'GREENCARE Zestaw to kompleksowy, profesjonalny program pielęgnacyjny, który działa synergicznie na włosy i skórę głowy. Zestaw składa się z trzech produktów: fluidu, szamponu oraz emulsji, które wspólnie zapewniają oczyszczenie, regenerację oraz ochronę włókna włosa. Formuły produktów z linii GREENCARE bazują na starannie dobranych składnikach aktywnych, które wspierają naturalną równowagę włosów i skóry głowy. Szampon delikatnie oczyszcza, usuwając zanieczyszczenia i pozostałości po zabiegach chemicznych, jednocześnie przygotowując włosy do dalszej pielęgnacji. Fluid działa ochronnie i regenerująco, wzmacnia strukturę włosa oraz poprawia jego kondycję. Emulsja intensywnie pielęgnuje, nawilża i wygładza włókno włosa, przywracając mu miękkość, elastyczność i naturalny blask. GREENCARE Zestaw polecany jest szczególnie do włosów osłabionych, uwrażliwionych, po koloryzacji, rozjaśnianiu lub innych zabiegach technicznych. Regularne stosowanie pomaga poprawić wygląd włosów, ułatwia rozczesywanie oraz chroni przed dalszymi uszkodzeniami, pozostawiając włosy zdrowe, lekkie i pełne życia.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'zestawy'), '/produkty/GreenLifeSet.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/12/GreenLifeSet.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'peach-shampoo-szampon-oczyszczajacy-10l', 'Peach Shampoo - szampon oczyszczający 10L', 'Brzoskwiniowy szampon oczyszczający Chenice delikatnie, a jednocześnie skutecznie usuwa zanieczyszczenia i pozostałości po zabiegach stylizacyjnych. Odświeża włosy i skórę głowy, pozostawiając je lekkie, czyste i pełne blasku.', 'PEACH SHAMPOO Chenice to profesjonalny szampon oczyszczający, stworzony do dokładnego, ale łagodnego mycia włosów i skóry głowy. Jego formuła skutecznie usuwa nadmiar sebum, zanieczyszczenia środowiskowe oraz pozostałości kosmetyków do stylizacji, nie naruszając naturalnej równowagi włosów. Szampon przygotowuje włosy do dalszych zabiegów pielęgnacyjnych i technicznych, poprawiając wchłanianie składników aktywnych stosowanych w kolejnych etapach. Lekka, brzoskwiniowa formuła odświeża włosy, nadaje im miękkość i naturalny połysk, nie obciążając ich. PEACH SHAMPOO polecany jest do każdego rodzaju włosów, szczególnie przed zabiegami regeneracyjnymi, koloryzacją lub intensywną pielęgnacją. Regularne stosowanie pomaga zachować świeżość, lekkość i zdrowy wygląd włosów oraz skóry głowy.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'odbudowa-wlosow'), '/produkty/Peach10L.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/12/Peach10L.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'kerabond-summer-shampoo-250-ml', 'Kerabond Summer Shampoo 250 ml', 'Szampon ochronny do włosów narażonych na słońce, sól morską i chlor. Delikatnie oczyszcza, nawilża i pomaga zachować miękkość oraz blask włosów w okresie letnim.', 'KERABOND SUMMER SHAMPOO Chenice to łagodny szampon przeznaczony do pielęgnacji włosów podczas ekspozycji na słońce, wodę morską i basenową. Skutecznie usuwa zanieczyszczenia, sól i chlor, jednocześnie dbając o odpowiedni poziom nawilżenia włókna włosa. Formuła pomaga chronić strukturę włosów przed przesuszeniem, utratą elastyczności i matowieniem. Włosy po umyciu stają się miękkie, łatwe do rozczesania i pełne naturalnego blasku. Szampon polecany do codziennego stosowania latem, dla każdego rodzaju włosów, również farbowanych.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/HAIR-BODY-SHAMPOO-1.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/12/HAIR-BODY-SHAMPOO-1.png","https://cbh-polska.pl/wp-content/uploads/2025/12/Espositore-Kerond-Summer-1024x831-1.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'kerabond-summer-mask-200-ml', 'Kerabond Summer Mask 200 ml', 'Maska regenerująca do włosów osłabionych przez słońce, sól i chlor. Intensywnie odżywia, nawilża i przywraca włosom miękkość oraz elastyczność.', 'KERABOND SUMMER MASK Chenice to intensywna maska pielęgnacyjna, stworzona z myślą o włosach narażonych na letnie czynniki zewnętrzne. Pomaga regenerować włókno włosa, uzupełniając utracone nawilżenie i poprawiając jego kondycję. Regularne stosowanie maski sprawia, że włosy stają się bardziej elastyczne, gładkie i odporne na łamliwość. Produkt ułatwia rozczesywanie, wygładza powierzchnię włosa i pomaga przywrócić zdrowy wygląd po ekspozycji na słońce, wiatr oraz wodę morską lub basenową.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/HYDRATING-MASK-1.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/12/HYDRATING-MASK-1.png","https://cbh-polska.pl/wp-content/uploads/2025/12/Espositore-Kerond-Summer-1024x831-1.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'kerabond-summer-spray-150-ml', 'Kerabond Summer Spray 150 ml', 'Ochronny spray bez spłukiwania do włosów wystawionych na działanie słońca. Chroni, nawilża i zapobiega przesuszeniu oraz puszeniu się włosów.', 'KERABOND SUMMER SPRAY Chenice to lekki spray bez spłukiwania, przeznaczony do ochrony włosów w trakcie ekspozycji na słońce. Tworzy na włosach warstwę ochronną, która pomaga ograniczyć negatywne działanie promieni UV, soli morskiej i chloru. Produkt nawilża włosy, zapobiega ich przesuszeniu oraz ułatwia stylizację. Może być stosowany na suche lub wilgotne włosy, zarówno na plaży, jak i w codziennej pielęgnacji. Włosy pozostają miękkie, lekkie i bardziej odporne na uszkodzenia.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/PROTECTIVE-SPRAY-1.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/12/PROTECTIVE-SPRAY-1.png","https://cbh-polska.pl/wp-content/uploads/2025/12/Espositore-Kerond-Summer-1024x831-1.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'kerabond-summer-shiny-body-krem-150ml', 'Kerabond Summer Shiny Body krem 150ml', 'Emolientowy krem do ciała z drobinkami rozświetlającymi. Pozostawia skórę jedwabiście gładką, nawilżoną i subtelnie rozświetloną, podkreślając opaleniznę.', 'SHINY BODY CREAM to lekka, emolientowa emulsja do pielęgnacji ciała, wzbogacona drobinkami rozświetlającymi. Krem nadaje skórze jedwabistą miękkość oraz naturalny blask, pomagając podkreślić i uwydatnić opaleniznę. Formuła łatwo się rozprowadza i szybko wchłania, nie pozostawiając uczucia lepkości. Regularne stosowanie sprawia, że skóra wygląda na gładką, zadbaną i promienną. Produkt idealnie sprawdzi się do codziennej pielęgnacji, szczególnie po kąpieli lub prysznicu. Sposób użycia Nałożyć na całe ciało i delikatnie wmasować do całkowitego wchłonięcia. Idealny do stosowania po prysznicu.',
  (select id from brands where slug = 'chenice'), (select id from categories where slug = 'inne'), '/produkty/Shiny-body-cream-1.png', '{"https://cbh-polska.pl/wp-content/uploads/2025/12/Shiny-body-cream-1.png","https://cbh-polska.pl/wp-content/uploads/2025/12/Espositore-Kerond-Summer-1024x831-1.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'he-she-spray-direct-400ml', 'He.She Spray Direct 400ml', 'Precyzyjny spray kierunkowy o silnym utrwaleniu.', 'Spray kierunkowy bez gazu idealny do fryzur strukturalnych. Pozwala na precyzyjne kształtowanie włosów według własnych upodobań, nadając im definicję i kształt przy zachowaniu elastyczności.',
