) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'he-she-spray-gloss-300ml', 'He.She Spray Gloss 300ml', 'Spray nabłyszczający z efektem anti-frizz.', 'Unikalna formuła przeciw puszeniu chroni włosy przed wilgocią i nadaje ekstra błyszczące wykończenie. Włosy stają się miękkie, niezwykle lśniące i chronione przed elektryzowaniem.',
  (select id from brands where slug = '6-zero'), (select id from categories where slug = 'stylizacja'), '/produkty/6zero/262465_sei_punto_zero_heshe_spray_gloss_shining_300ml.png', '{"https://cbh-polska.pl/wp-content/uploads/2026/02/262465_sei_punto_zero_heshe_spray_gloss_shining_300ml.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'anti-orange-500-ml', 'Anti Orange 500 ml', 'Szampon anty-pomarańczowy', 'Szampon Take Over Out Orange został stworzony, aby zredukować pomarańczowe tony, które mogą pojawić się na ciemnych włosach. Łączy delikatne oczyszczanie z intensywnym działaniem nawilżającym, neutralizując ciepłe miedziane i rude odcienie. Włosy są bardziej promienne, a ciemne tony głębsze. Ten szampon anty-pomarańczowy został specjalnie zaprojektowany, aby chronić piękno naturalnych lub farbowanych włosów.',
  (select id from brands where slug = '6-zero'), (select id from categories where slug = 'szampony'), '/produkty/6zero/262670_sei_punto_zero_take_over_out_orange_shampoo_500ml-1.png', '{"https://cbh-polska.pl/wp-content/uploads/2026/02/262670_sei_punto_zero_take_over_out_orange_shampoo_500ml-1.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'he-she-therm-screen-200ml', 'He.She Therm Screen 200ml', 'Termoochronny spray wygładzający.', 'Chroni włosy przed wysokimi temperaturami podczas stylizacji. Dzięki kwasowi hialuronowemu w składzie, włosy zachowują nawilżenie, połysk i miękkość, minimalizując uszkodzenia spowodowane gorącem.',
  (select id from brands where slug = '6-zero'), (select id from categories where slug = 'stylizacja'), '/produkty/6zero/262656_sei_punto_zero_heshe_therm_screen_smoothing_spray_200ml.png', '{"https://cbh-polska.pl/wp-content/uploads/2026/02/262656_sei_punto_zero_heshe_therm_screen_smoothing_spray_200ml.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
