insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'hairzoe-cream-500ml', 'Hairzoe Cream 500ml', 'Kremowa kuracja do włosów.', 'Bogata kremowa kuracja zapewniająca głębokie odżywienie i regenerację włosów. Idealna do stosowania w salonie lub w domu jako intensywna terapia pielęgnacyjna.',
  (select id from brands where slug = '6-zero'), (select id from categories where slug = 'odbudowa-wlosow'), '/produkty/6zero/263158_sei_punto_zero_hairzoe_restructuring_base_cream_500ml.png', '{"https://cbh-polska.pl/wp-content/uploads/2026/02/263158_sei_punto_zero_hairzoe_restructuring_base_cream_500ml.png"}', true, ''
