insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'hairzoe-mask-250ml', 'Hairzoe Mask 250ml', 'Maska regenerująca do włosów.', 'Intensywna maska do włosów wymagających regeneracji. Formuła wzbogacona składnikami aktywnymi przywraca włosom zdrowy wygląd, miękkość i blask.',
  (select id from brands where slug = '6-zero'), (select id from categories where slug = 'odbudowa-wlosow'), '/produkty/6zero/263189_sei_punto_zero_hairzoe_post_restructuring_mask_250ml.png', '{"https://cbh-polska.pl/wp-content/uploads/2026/02/263189_sei_punto_zero_hairzoe_post_restructuring_mask_250ml.png"}', true, ''
