insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'hairzoe-spray-150ml', 'Hairzoe Spray 150ml', 'Spray pielęgnacyjny bez spłukiwania.', 'Spray Hairzoe to końcowy etap zabiegu salonowego, oferujący działanie regenerujące i rozświetlające. Został zaprojektowany, aby nadać włosom energii oraz poprawić ich siłę i blask. Formuła chroni długości, zamyka łuski włosa i przygotowuje go do szczotkowania. Koncentracja kwasu hialuronowego i komórek macierzystych winogron wzmacnia właściwości regenerujące i ochronne zabiegu dla suchych, łamliwych i zniszczonych włosów.',
  (select id from brands where slug = '6-zero'), (select id from categories where slug = 'odbudowa-wlosow'), '/produkty/6zero/263172_sei_punto_zero_hairzoe_restructuring_spray_150ml.png', '{"https://cbh-polska.pl/wp-content/uploads/2026/02/263172_sei_punto_zero_hairzoe_restructuring_spray_150ml.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
