  (select id from brands where slug = '6-zero'), (select id from categories where slug = 'odbudowa-wlosow'), '/produkty/6zero/263165_sei_punto_zero_hairzoe_restructuring_booster_serum_10ml.png', '{"https://cbh-polska.pl/wp-content/uploads/2026/02/263165_sei_punto_zero_hairzoe_restructuring_booster_serum_10ml.png"}', true, ''
