insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'oxy-20-vol-200-ml', 'Oxy 20 vol 200 ml', 'Emulsja utleniająca do koloryzacji.', 'Zapachowa emulsja utleniająca do koloryzacji kosmetycznej. Kremowa, delikatnie zapachowa emulsja utleniająca jest idealnym uzupełnieniem koloryzacji 6.Zero, podkreślając jej właściwości, jednocześnie kondycjonując i chroniąc oraz zatrzymując wilgoć i blask włosów podczas koloryzacji. Wysoce stabilny zemulgowany nadtlenek wodoru 6.Zero pozwala na całkowitą swobodę koloryzacji lub rozjaśniania włosów z poszanowaniem włókna włosowatego włosa. Wyłącznie do użytku profesjonalnego. Butelka 200 ml',
  (select id from brands where slug = '6-zero'), (select id from categories where slug = 'koloryzacja'), '/produkty/6zero/262052_sei_punto_zero_oxidizing_emulsion_20vol_200ml-1.png', '{"https://cbh-polska.pl/wp-content/uploads/2026/02/262052_sei_punto_zero_oxidizing_emulsion_20vol_200ml-1.png"}', true, ''
