insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'sun-deluxe-szampon-300-ml', 'Sun Deluxe szampon 300 ml', 'Szampon/żel pod prysznic po opalaniu Take Over Sun Deluxe zapewnia wzmocniony blask i ochronę.', 'Szampon/żel pod prysznic po opalaniu Take Over Sun Deluxe zapewnia wzmocniony blask i ochronę. Delikatnie oczyszcza ciało i włosy po narażeniu na czynniki zewnętrzne: promienie UV, sól i chlor. Jego formuła, wzbogacona witaminą E i polifenolami, zapewnia właściwości ochronne i przywraca naturalne nawilżenie, przynosząc miękkość skórze i blask włosom. 300 ml',
  (select id from brands where slug = '6-zero'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/6zero/263226_sei_punto_zero_take_over_sun_deluxe_shampoo_300ml.png', '{"https://cbh-polska.pl/wp-content/uploads/2026/02/263226_sei_punto_zero_take_over_sun_deluxe_shampoo_300ml.png"}', true, ''
