insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'hy-plex-zestaw-1-1-2-2', 'Hy-Plex zestaw 1+1+ 2+2', '', '599Innowacja zaczyna się od wewnątrz: HY-PLEX to ekskluzywny zabieg, który rewolucjonizuje podejście do usług technicznych, rewitalizując włosy uszkodzone przez zabiegi chemiczne. Specjalna formuła z technologią HP2 oferuje włosom maksymalną ochronę przed i po usługach koloryzacji, rozjaśniania i trwałej ondulacji. Rezultat: miękkie włosy o niespotykanym blasku. Zestaw zawiera: 1 butelkę HY-PLEX No.1 (500 ml): Dodatek ochronny do usług technicznych 2 butelki HY-PLEX No.2 (500 ml): Wzmacniająca maska po zabiegu',
  null, (select id from categories where slug = 'odbudowa-wlosow'), '/produkty/6zero/263158_sei_punto_zero_hairzoe_restructuring_base_cream_500ml262991_sei_punto_zero_hy_plex_kit_2.png', '{"https://cbh-polska.pl/wp-content/uploads/2026/02/263158_sei_punto_zero_hairzoe_restructuring_base_cream_500ml262991_sei_punto_zero_hy_plex_kit_2.png"}', true, ''
) on conflict (slug) do update set name = excluded.name, short_description = excluded.short_description, description = excluded.description, brand_id = excluded.brand_id, primary_category_id = excluded.primary_category_id, image = excluded.image, images = excluded.images, in_stock = excluded.in_stock, variant_attribute = excluded.variant_attribute;
insert into products (slug, name, short_description, description, brand_id, primary_category_id, image, images, in_stock, variant_attribute) values (
  'active-sheer-shampoo-300-ml', 'Active Sheer Shampoo 300 ml', 'Szampon podwójnego działania do przetłuszczającej się skóry głowy.', 'TAKE OVER · ACTIVE SHEER Szampon podwójnego działania do przetłuszczającej się skóry głowy, z łupieżem i suchymi włosami Szampon podwójnego działania do przetłuszczającej się skóry głowy, z łupieżem i suchymi włosami o delikatnie oczyszczającym działaniu. Oczyszcza skórę głowy, dzięki Piroctone Olamine i kwasowi salicylowemu, które pomagają zmniejszyć powstawanie łupieżu i redukują nadmiar sebum, przywracając równowagę i świeżość włosom. Ekstrakt z rozmarynu wspomaga głębokie oczyszczanie włosów, z intensywnym działaniem antyoksydacyjnym. Butelka 300 ml',
  (select id from brands where slug = '6-zero'), (select id from categories where slug = 'ochrona-wlosow'), '/produkty/6zero/263264_sei_punto_zero_take_over_active_sheer_shampoo_300ml-1.png', '{"https://cbh-polska.pl/wp-content/uploads/2026/02/263264_sei_punto_zero_take_over_active_sheer_shampoo_300ml-1.png"}', true, ''
